        HttpGet httpGet = new HttpGet(uri);
        httpGet.setConfig(requestConfig);
        httpGet.setHeader(HttpHeaders.ACCEPT, "*/*");
        httpGet.setHeader(HttpHeaders.USER_AGENT, "UrlService/1.0");

        try (CloseableHttpClient httpClient = HttpClients.createDefault();
             CloseableHttpResponse response = httpClient.execute(httpGet)) {

            int statusCode = response.getStatusLine().getStatusCode();
            if (statusCode < HttpStatus.SC_OK || statusCode >= HttpStatus.SC_MULTIPLE_CHOICES) {
                throw new RuntimeException("Failed to fetch URL content. HTTP status: " + statusCode);
            }

            HttpEntity entity = response.getEntity();
            if (entity == null) {
                return "";
            }

            long contentLength = entity.getContentLength();
            if (contentLength > MAX_RESPONSE_SIZE_BYTES) {
                throw new RuntimeException("Response content is too large");
            }

            byte[] contentBytes = EntityUtils.toByteArray(entity);
            if (contentBytes.length > MAX_RESPONSE_SIZE_BYTES) {
                throw new RuntimeException("Response content is too large");
            }

            return new String(contentBytes, StandardCharsets.UTF_8);
        } catch (ClientProtocolException e) {
            throw new RuntimeException("HTTP protocol error while fetching URL content", e);
        } catch (IOException e) {
            throw new RuntimeException("I/O error while fetching URL content", e);
        }
    }

    private URI buildAndValidateUri(String userUrl) {
        try {
            URI uri = new URIBuilder(userUrl).build();
            String scheme = uri.getScheme();

            if (scheme == null) {
                throw new IllegalArgumentException("URL must include a scheme");
            }

            if (!"http".equalsIgnoreCase(scheme) && !"https".equalsIgnoreCase(scheme)) {
                throw new IllegalArgumentException("Only HTTP and HTTPS URLs are allowed");
            }

            String host = uri.getHost();
            if (host == null || host.trim().isEmpty()) {
                throw new IllegalArgumentException("URL must include a valid host");
            }

            if (isLocalAddress(host)) {
                throw new IllegalArgumentException("Local and loopback addresses are not allowed");
            }

            return uri;
        } catch (URISyntaxException e) {
            throw new IllegalArgumentException("Invalid URL format", e);
        }
    }

    private boolean isLocalAddress(String host) {
        String normalizedHost = host.toLowerCase();

        return "localhost".equals(normalizedHost)
                || "127.0.0.1".equals(normalizedHost)
                || "::1".equals(normalizedHost)
                || normalizedHost.startsWith("127.")
                || normalizedHost.startsWith("10.")
                || normalizedHost.startsWith("192.168.")
                || normalizedHost.matches("^172\\.(1[6-9]|2\\d|3[0-1])\\..*");
    }
}
